// ─── Helpers ──────────────────────────────────────────────────────────────────
function formatDate(iso: string) {
  return new Date(iso).toLocaleDateString("en-GB", {
    day: "numeric", month: "long", year: "numeric",
    hour: "2-digit", minute: "2-digit",
  });
}

function formatShortDate(iso: string) {
  return new Date(iso).toLocaleDateString("en-GB", { day: "numeric", month: "short" });
}

function getVideoEmbedUrl(url: string): string | null {
  const ytMatch = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]+)/);
  if (ytMatch) return `https://www.youtube.com/embed/${ytMatch[1]}`;
  const vimeoMatch = url.match(/vimeo\.com\/(\d+)/);
  if (vimeoMatch) return `https://player.vimeo.com/video/${vimeoMatch[1]}`;
  return null;
}

// ─── Blob URL Hook (bypasses Content-Disposition: attachment for PDFs) ─────────
function useBlobUrl(url: string | null) {
  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(false);

  useEffect(() => {
    if (!url) return;
    let revoked = false;
    setLoading(true);
    setError(false);
    setBlobUrl(null);
    fetch(url)
      .then(r => r.blob())
      .then(blob => {
        if (!revoked) {
          setBlobUrl(URL.createObjectURL(blob));
          setLoading(false);
        }
      })
      .catch(() => {
        if (!revoked) { setError(true); setLoading(false); }
      });
    return () => {
      revoked = true;
      setBlobUrl(prev => { if (prev) URL.revokeObjectURL(prev); return null; });
    };
  }, [url]);

  return { blobUrl, loading, error };
}

// ─── PDF Viewer ────────────────────────────────────────────────────────────────
function PdfViewer({ url, title }: { url: string; title: string }) {
  const { blobUrl, loading, error } = useBlobUrl(url);

  if (loading) {
    return (
      <div className="rounded-xl bg-[#FBF8FF] border border-[#EDE5F8] flex flex-col items-center justify-center py-16 gap-3">
        <div className="w-8 h-8 rounded-full border-2 border-[#8A2BE2] border-t-transparent animate-spin" />
        <p className="text-[13px] text-[#A08DBE]">Loading PDF…</p>
      </div>
    );
  }

  const iframeSrc = error || !blobUrl
    ? `https://docs.google.com/gview?url=${encodeURIComponent(url)}&embedded=true`
    : blobUrl;

  return (
    <div className="rounded-xl overflow-hidden border border-[#EDE5F8] flex flex-col">
      <iframe
        src={iframeSrc}
        className="w-full border-0"
        style={{ height: 520 }}
        title={title}
      />
      <div className="flex items-center justify-between px-4 py-2.5 bg-[#FBF8FF] border-t border-[#EDE5F8]">
        <span className="text-[11px] text-[#A08DBE]">
          {error ? "Viewing via Google Docs" : "PDF preview"}
        </span>
        <a
          href={url}
          target="_blank"
          rel="noopener noreferrer"
          className="inline-flex items-center gap-1 text-[11px] font-semibold text-[#8A2BE2] hover:underline"
        >
          {Icon.externalLink} Open original
        </a>
      </div>
    </div>
  );
}

// ─── Preview Body ─────────────────────────────────────────────────────────────
function PreviewBody({ item }: { item: ContentResponse }) {
  const fileUrl = (item as any).file_url ?? null;
  const textBody = (item as any).text_body ?? (item as any).body ?? null;
  const thumbnailUrl = (item as any).thumbnail_url ?? null;

  if (item.content_type === "video") {
    if (!fileUrl) {
      return (
        <div className="rounded-xl bg-[#1a0030] flex flex-col items-center justify-center py-16 gap-3">
          <div className="w-14 h-14 rounded-full bg-white/10 flex items-center justify-center text-white/60">{Icon.play}</div>
          <p className="text-[13px] text-white/40">Video not available</p>
        </div>
      );
    }
    const embedUrl = getVideoEmbedUrl(fileUrl);
    if (embedUrl) {
      return (
        <div className="rounded-xl overflow-hidden bg-black" style={{ aspectRatio: "16/9" }}>
          <iframe
            src={embedUrl}
            className="w-full h-full"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          />
        </div>
      );
    }
    return (
      <div className="rounded-xl overflow-hidden bg-black">
        <video
          src={fileUrl}
          controls
          className="w-full max-h-[480px]"
          poster={thumbnailUrl ?? undefined}
          preload="metadata"
          playsInline
        />
      </div>
    );
  }

  if (item.content_type === "image") {
    const src = fileUrl ?? thumbnailUrl;
    if (!src) {
      return (
        <div className="rounded-xl bg-[#FBF8FF] border-2 border-dashed border-[#EDE5F8] flex items-center justify-center py-16">
          <p className="text-[13px] text-[#A08DBE]">Image not available</p>
        </div>
      );
    }
    return (
      <div className="rounded-xl overflow-hidden bg-[#F5EFFF] border border-[#EDE5F8] flex items-center justify-center">
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img src={src} alt={item.title} className="max-w-full max-h-[480px] object-contain" />
      </div>
    );
  }

  if (item.content_type === "pdf") {
    if (!fileUrl) {
      return (
        <div className="rounded-xl bg-[#FBF8FF] border-2 border-dashed border-[#EDE5F8] flex flex-col items-center justify-center py-16 gap-3">
          <div className="w-12 h-12 rounded-xl bg-[#F3E8FF] border border-[#EDE5F8] flex items-center justify-center text-[#8A2BE2]">{Icon.file}</div>
          <p className="text-[13px] text-[#A08DBE]">PDF not available</p>
        </div>
      );
    }
    return <PdfViewer url={fileUrl} title={item.title} />;
  }

  if (item.content_type === "text") {
    if (!textBody) {
      return (
        <div className="rounded-xl bg-[#FBF8FF] border-2 border-dashed border-[#EDE5F8] flex items-center justify-center py-16">
          <p className="text-[13px] text-[#A08DBE]">Content is empty</p>
        </div>
      );
    }
    return (
      <div className="rounded-xl bg-[#FBF8FF] border border-[#EDE5F8] px-6 py-5">
        <div
          className="text-[14.5px] text-[#2D0052] leading-[1.8] whitespace-pre-wrap"
          style={{ fontFamily: "'Georgia', serif" }}
        >
          {textBody}
        </div>
      </div>
    );
  }

  return null;
}

// ─── Thumbnail (used in grid/list cards on the dashboard) ─────────────────────
interface ContentThumbnailProps {
  item: ContentResponse;
  onClick: () => void;
  /** When used in a list row, use compact variant */
  compact?: boolean;
}

export function ContentThumbnail({ item, onClick, compact = false }: ContentThumbnailProps) {
  const fileUrl = (item as any).file_url ?? (item as any).url ?? null;
  const thumbnailUrl = (item as any).thumbnail_url ?? null;
  const textBody = (item as any).text_body ?? (item as any).body ?? null;

  const height = compact ? "h-[56px] w-[80px]" : "w-full";
  const aspectStyle = compact ? {} : { aspectRatio: "16/10" };

  return (
    <div
      onClick={onClick}
      className={`relative cursor-pointer rounded-xl overflow-hidden bg-[#F3E8FF] border border-[#EDE5F8] group/thumb transition-all hover:border-[#A78BFA] hover:shadow-md shrink-0 ${height}`}
      style={aspectStyle}
    >
      {/* VIDEO */}
      {item.content_type === "video" && (
        fileUrl || thumbnailUrl ? (
          <>
            {thumbnailUrl
              ? <img src={thumbnailUrl} alt="" className="w-full h-full object-cover" />
              : <div className="w-full h-full bg-[#1a0030]" />
            }
            <div className="absolute inset-0 bg-black/30 flex items-center justify-center group-hover/thumb:bg-black/10 transition-all">
              <div className={`${compact ? "w-7 h-7" : "w-10 h-10"} rounded-full bg-white/90 flex items-center justify-center text-[#8A2BE2] shadow-lg`}>
                {Icon.play}
              </div>
            </div>
          </>
        ) : (
          <div className="w-full h-full bg-[#1a0030] flex items-center justify-center text-white/30">
            {Icon.play}
          </div>
        )
      )}

      {/* IMAGE */}
      {item.content_type === "image" && (
        (fileUrl || thumbnailUrl) ? (
          // eslint-disable-next-line @next/next/no-img-element
          <img src={fileUrl ?? thumbnailUrl} alt={item.title} className="w-full h-full object-cover" />
        ) : (
          <div className="w-full h-full flex items-center justify-center text-[#C4B5D4]">
            <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round">
              <rect x="2" y="2" width="16" height="16" rx="3" /><circle cx="7" cy="7.5" r="1.5" /><path d="M2 14l4-4 3 3 3-4 6 6" />
            </svg>
          </div>
        )
      )}

      {/* PDF */}
      {item.content_type === "pdf" && (
        <div className="w-full h-full flex flex-col items-center justify-center gap-1 bg-[#FBF8FF]">
          <div className={`${compact ? "w-6 h-6" : "w-8 h-8"} rounded-lg bg-[#F3E8FF] border border-[#EDE5F8] flex items-center justify-center text-[#8A2BE2]`}>{Icon.file}</div>
          {!compact && <p className="text-[9px] text-[#A08DBE] font-semibold uppercase tracking-wide">PDF</p>}
        </div>
      )}

      {/* TEXT */}
      {item.content_type === "text" && (
        <div className="w-full h-full p-2 bg-[#FBF8FF] flex flex-col justify-start overflow-hidden">
          {textBody ? (
            <p className="text-[9px] text-[#6B4F8A] leading-[1.5] line-clamp-4" style={{ fontFamily: "'Georgia', serif" }}>
              {textBody}
            </p>
          ) : (
            <div className="flex items-center justify-center h-full text-[#C4B5D4]">
              <svg width="16" height="16" viewBox="0 0 18 18" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round">
                <path d="M3 4h12M3 8h8M3 12h10M3 16h6" />
              </svg>
            </div>
          )}
        </div>
      )}

      {/* Hover hint */}
      {!compact && (
        <div className="absolute inset-0 flex items-end justify-end p-2 opacity-0 group-hover/thumb:opacity-100 transition-opacity pointer-events-none">
          <span className="flex items-center gap-1 text-[10px] font-semibold bg-black/60 text-white px-2 py-1 rounded-full backdrop-blur-sm">
            {Icon.expand} Expand
          </span>
        </div>
      )}
    </div>
  );
}

// ─── Full-screen Content Preview Modal ────────────────────────────────────────
interface ContentPreviewModalProps {
  item: ContentResponse;
  allItems?: ContentResponse[];
  onClose: () => void;
  onNavigate?: (item: ContentResponse) => void;
  /** Show publish/unpublish button (creator view) */
  canPublish?: boolean;
  onTogglePublish?: (id: number) => void;
  isTogglingPublish?: boolean;
}

export function ContentPreviewModal({
  item,
  allItems = [],
  onClose,
  onNavigate,
  canPublish = false,
  onTogglePublish,
  isTogglingPublish,
}: ContentPreviewModalProps) {
  const currentIndex = allItems.findIndex(i => i.id === item.id);
  const prevItem = onNavigate && currentIndex > 0 ? allItems[currentIndex - 1] : null;
  const nextItem = onNavigate && currentIndex < allItems.length - 1 ? allItems[currentIndex + 1] : null;

  const fileUrl = (item as any).file_url ?? (item as any).url ?? null;
  const tCfg = CONTENT_TYPE_CONFIG[item.content_type];

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose();
      if (e.key === "ArrowLeft" && prevItem && onNavigate) onNavigate(prevItem);
      if (e.key === "ArrowRight" && nextItem && onNavigate) onNavigate(nextItem);
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose, onNavigate, prevItem, nextItem]);

  useEffect(() => {
    document.body.style.overflow = "hidden";
    return () => { document.body.style.overflow = ""; };
  }, []);

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center"
      style={{ background: "rgba(18, 0, 35, 0.72)", backdropFilter: "blur(8px)" }}
      onClick={onClose}
    >
      {/* Prev/Next nav */}
      {prevItem && onNavigate && (
        <button
          onClick={e => { e.stopPropagation(); onNavigate(prevItem); }}
          className="absolute left-4 top-1/2 -translate-y-1/2 z-[60] w-10 h-10 rounded-full bg-white/10 hover:bg-white/25 border border-white/10 flex items-center justify-center text-white transition-all backdrop-blur-sm"
          title="Previous (←)"
        >
          {Icon.arrowLeft}
        </button>
      )}
      {nextItem && onNavigate && (
        <button
          onClick={e => { e.stopPropagation(); onNavigate(nextItem); }}
          className="absolute right-4 top-1/2 -translate-y-1/2 z-[60] w-10 h-10 rounded-full bg-white/10 hover:bg-white/25 border border-white/10 flex items-center justify-center text-white transition-all backdrop-blur-sm"
          title="Next (→)"
        >
          {Icon.arrowRight}
        </button>
      )}

      <div
        className="bg-white w-full max-w-[740px] max-h-[92vh] rounded-2xl border border-[#EDE5F8] overflow-hidden flex flex-col"
        style={{ boxShadow: "0 40px 100px rgba(18, 0, 35, 0.4)" }}
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center gap-3 px-6 pt-5 pb-4 border-b border-[#F5EFFF] shrink-0">
          <div
            className="w-[34px] h-[34px] rounded-[9px] border flex items-center justify-center shrink-0 text-[10px] font-bold"
            style={{ background: `${tCfg.color}18`, borderColor: `${tCfg.color}30`, color: tCfg.color }}
          >
            {tCfg.icon}
          </div>
          <div className="flex-1 min-w-0">
            <h3 className="text-[16px] font-bold text-[#2D0052] truncate">{item.title}</h3>
            <div className="flex items-center gap-2 mt-0.5 flex-wrap">
              <span className="text-[11px] text-[#A08DBE]">{tCfg.label}</span>
              <span className="text-[11px] text-[#D4C5E8]">·</span>
              <span className="text-[11px] text-[#A08DBE]">{formatDate(item.created_at)}</span>
              {(item as any).view_count > 0 && (
                <>
                  <span className="text-[11px] text-[#D4C5E8]">·</span>
                  <span className="text-[11px] text-[#A08DBE]">{(item as any).view_count} views</span>
                </>
              )}
              {(item as any).like_count > 0 && (
                <>
                  <span className="text-[11px] text-[#D4C5E8]">·</span>
                  <span className="text-[11px] text-[#A08DBE] inline-flex items-center gap-0.5">{Icon.heart} {(item as any).like_count}</span>
                </>
              )}
            </div>
          </div>
          <button
            onClick={onClose}
            className="w-8 h-8 rounded-full bg-[#F5EFFF] flex items-center justify-center text-[#A08DBE] hover:bg-[#EDE5F8] hover:text-[#6B4F8A] transition-colors shrink-0"
          >
            {Icon.x}
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-auto">
          <div className="px-6 py-5 flex flex-col gap-4">
            <PreviewBody item={item} />

            {(item as any).description && (
              <p className="text-[13.5px] text-[#6B4F8A] leading-relaxed px-1">{(item as any).description}</p>
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between px-6 py-4 border-t border-[#F5EFFF] shrink-0 bg-[#FBF8FF]">
          <div className="flex items-center gap-2 flex-wrap">
            {/* Published/draft badge */}
            <span className={`inline-flex items-center gap-1.5 text-[11px] font-semibold px-2.5 py-1 rounded-full ${
              item.is_published ? "bg-[#DCFCE7] text-[#166534]" : "bg-[#F5EFFF] text-[#A08DBE] border border-[#EDE5F8]"
            }`}>
              <span className={`w-1.5 h-1.5 rounded-full shrink-0 ${item.is_published ? "bg-[#16A34A]" : "bg-[#A08DBE]"}`} />
              {item.is_published ? "Published" : "Draft"}
            </span>

            {/* Plan access */}
            <span className="inline-flex items-center text-[11px] font-bold px-2.5 py-1 rounded-full bg-[#F3E8FF] text-[#8A2BE2] border border-[#EDE5F8]">
              {item.plans?.length > 0 ? item.plans.map(p => p.name).join(", ") : "All subscribers"}
            </span>

            {/* Navigation counter */}
            {allItems.length > 1 && (
              <span className="text-[11px] text-[#C4B5D4]">{currentIndex + 1} / {allItems.length}</span>
            )}
          </div>

          <div className="flex items-center gap-2">
            {canPublish && onTogglePublish && (
              <button
                onClick={() => onTogglePublish(item.id)}
                disabled={isTogglingPublish}
                className="inline-flex items-center gap-1.5 text-[12px] font-semibold px-3 py-1.5 rounded-lg border bg-white text-[#6B4F8A] border-[#EDE5F8] hover:bg-[#F5EFFF] hover:border-[#DDD6FE] transition-all disabled:opacity-50"
              >
                {Icon.eye}
                {item.is_published ? "Unpublish" : "Publish"}
              </button>
            )}

            {fileUrl && (
              <a
                href={fileUrl}
                download={item.title}
                target="_blank"
                rel="noopener noreferrer"
                className="inline-flex items-center gap-1.5 text-[12px] font-semibold px-3 py-1.5 rounded-lg border bg-white text-[#6B4F8A] border-[#EDE5F8] hover:bg-[#F5EFFF] hover:border-[#DDD6FE] transition-all"
              >
                {Icon.download} Download
              </a>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Inline Peek (expands inside a row/card without opening modal) ─────────────
interface InlinePeekProps {
  item: ContentResponse;
  onOpenFull: () => void;
}

export function InlinePeek({ item, onOpenFull }: InlinePeekProps) {
  const fileUrl = (item as any).file_url ?? null;
  const textBody = (item as any).text_body ?? (item as any).body ?? null;
  const thumbnailUrl = (item as any).thumbnail_url ?? null;

  return (
    <div className="border-t border-[#F5EFFF] bg-[#FBF8FF]">
      <div className="mx-5 mt-3 mb-2">
        {item.content_type === "text" && textBody && (
          <div className="rounded-xl bg-white border border-[#EDE5F8] px-5 py-4">
            <p
              className="text-[13px] text-[#2D0052] leading-relaxed whitespace-pre-wrap line-clamp-6"
              style={{ fontFamily: "'Georgia', serif" }}
            >
              {textBody}
            </p>
          </div>
        )}

        {item.content_type === "image" && (fileUrl || thumbnailUrl) && (
          <div className="rounded-xl overflow-hidden border border-[#EDE5F8] bg-[#F5EFFF] flex items-center justify-center" style={{ maxHeight: 280 }}>
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img
              src={fileUrl ?? thumbnailUrl}
              alt={item.title}
              className="max-w-full object-contain"
              style={{ maxHeight: 280 }}
            />
          </div>
        )}

        {item.content_type === "video" && fileUrl && (() => {
          const embedUrl = getVideoEmbedUrl(fileUrl);
          return embedUrl ? (
            <div className="rounded-xl overflow-hidden bg-black" style={{ aspectRatio: "16/9" }}>
              <iframe
                src={embedUrl}
                className="w-full h-full"
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                allowFullScreen
              />
            </div>
          ) : (
            <div className="rounded-xl overflow-hidden bg-black">
              <video
                src={fileUrl}
                controls
                className="w-full"
                poster={thumbnailUrl ?? undefined}
                preload="metadata"
                playsInline
                style={{ maxHeight: 280 }}
              />
            </div>
          );
        })()}

        {item.content_type === "pdf" && fileUrl && (
          <PdfViewer url={fileUrl} title={item.title} />
        )}
      </div>

      <div className="flex justify-end px-5 pb-3">
        <button
          onClick={onOpenFull}
          className="inline-flex items-center gap-1.5 text-[12px] font-semibold px-3 py-1.5 rounded-lg text-white transition-all"
          style={{ background: "#8A2BE2", boxShadow: "0 2px 8px rgba(138,43,226,0.25)" }}
        >
          {Icon.eye} Open full view
        </button>
      </div>
    </div>
  );
}

// ─── Dashboard Content Card ────────────────────────────────────────────────────
// Drop-in card for grid/feed layouts on the subscriber dashboard.
// Shows a thumbnail, opens full preview on click.
interface DashboardContentCardProps {
  item: ContentResponse;
  onPreview: (item: ContentResponse) => void;
}

export function DashboardContentCard({ item, onPreview }: DashboardContentCardProps) {
  const tCfg = CONTENT_TYPE_CONFIG[item.content_type];
  const isLocked = !item.is_published;

  return (
    <div
      className={`group bg-white rounded-2xl border overflow-hidden transition-all hover:shadow-lg ${
        isLocked ? "border-[#EDE5F8] opacity-70" : "border-[#EDE5F8] hover:border-[#DDD6FE]"
      }`}
      style={{ boxShadow: "0 1px 4px rgba(45,0,82,0.05)" }}
    >
      {/* Thumbnail */}
      <div className="p-2.5 pb-0">
        <ContentThumbnail item={item} onClick={() => !isLocked && onPreview(item)} />
      </div>

      {/* Card body */}
      <div className="px-3.5 pt-2.5 pb-3">
        <button
          onClick={() => !isLocked && onPreview(item)}
          className="w-full text-left mb-1.5"
          disabled={isLocked}
        >
          <span className="block text-[12.5px] font-semibold text-[#2D0052] truncate hover:text-[#8A2BE2] transition-colors leading-snug group-hover:text-[#8A2BE2]">
            {item.title}
          </span>
        </button>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-1.5">
            <span
              className="text-[9.5px] font-bold px-1.5 py-0.5 rounded-[4px] uppercase tracking-wide"
              style={{ background: `${tCfg.color}15`, color: tCfg.color }}
            >
              {tCfg.label}
            </span>
            <span className="text-[10.5px] text-[#C4B5D4]">{formatShortDate(item.created_at)}</span>
          </div>
          {isLocked && (
            <span className="inline-flex items-center gap-1 text-[10px] font-semibold text-[#A08DBE]">
              {Icon.lock} Locked
            </span>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── Dashboard Content Row (list view) ────────────────────────────────────────
// Compact list-style row with inline peek toggle.
interface DashboardContentRowProps {
  item: ContentResponse;
  onPreview: (item: ContentResponse) => void;
}

export function DashboardContentRow({ item, onPreview }: DashboardContentRowProps) {
  const [peekOpen, setPeekOpen] = useState(false);
  const tCfg = CONTENT_TYPE_CONFIG[item.content_type];
  const isLocked = !item.is_published;

  return (
    <div className="group flex flex-col border-b border-[#F5EFFF] last:border-b-0 transition-colors hover:bg-[#FBF8FF]">
      <div className="flex items-center gap-3 px-5 py-3">
        {/* Thumbnail thumb — clicking toggles inline peek */}
        <ContentThumbnail
          item={item}
          onClick={() => !isLocked && setPeekOpen(o => !o)}
          compact
        />

        <div className="flex-1 min-w-0">
          <button
            onClick={() => !isLocked && onPreview(item)}
            className="text-left w-full"
            disabled={isLocked}
          >
            <span className="block text-[13px] font-medium text-[#2D0052] truncate hover:text-[#8A2BE2] transition-colors">
              {item.title}
            </span>
            <span className="text-[11px] text-[#A08DBE]">{formatShortDate(item.created_at)}</span>
          </button>
        </div>

        <div className="flex items-center gap-2 shrink-0">
          <span
            className="hidden sm:inline text-[9.5px] font-bold px-1.5 py-0.5 rounded-[4px] uppercase tracking-wide"
            style={{ background: `${tCfg.color}15`, color: tCfg.color }}
          >
            {tCfg.label}
          </span>
          {isLocked ? (
            <span className="inline-flex items-center gap-1 text-[10.5px] font-semibold text-[#A08DBE] bg-[#F5EFFF] px-2 py-0.5 rounded-full border border-[#EDE5F8]">
              {Icon.lock} Locked
            </span>
          ) : (
            <button
              onClick={() => setPeekOpen(o => !o)}
              className={`inline-flex items-center gap-1 text-[10.5px] font-semibold px-2 py-0.5 rounded-full border transition-all ${
                peekOpen
                  ? "bg-[#8A2BE2] text-white border-[#8A2BE2]"
                  : "text-[#8A2BE2] bg-[#F3E8FF] border-[#EDE5F8] hover:border-[#A78BFA]"
              }`}
            >
              {Icon.eye} {peekOpen ? "Close" : "Peek"}
            </button>
          )}
        </div>
      </div>

      {peekOpen && !isLocked && (
        <InlinePeek item={item} onOpenFull={() => { onPreview(item); setPeekOpen(false); }} />
      )}
    </div>
  );
}

// ─── useContentPreview hook ────────────────────────────────────────────────────
// Convenience hook to wire up preview state and navigation in any parent component.
export function useContentPreview(items: ContentResponse[]) {
  const [previewItem, setPreviewItem] = useState<ContentResponse | null>(null);

  const openPreview = useCallback((item: ContentResponse) => setPreviewItem(item), []);
  const closePreview = useCallback(() => setPreviewItem(null), []);
  const navigatePreview = useCallback((item: ContentResponse) => setPreviewItem(item), []);

  const modal = previewItem ? (
    <ContentPreviewModal
      item={previewItem}
      allItems={items}
      onClose={closePreview}
      onNavigate={navigatePreview}
    />
  ) : null;

  return { openPreview, closePreview, navigatePreview, previewItem, modal };
}

// ─── Example: Subscriber Dashboard Feed ───────────────────────────────────────
// Shows how to use all the above in a dashboard content feed.
// Replace with your actual data fetching hooks.
interface SubscriberFeedProps {
  items: ContentResponse[];
  viewMode?: "grid" | "list";
}

export function SubscriberFeed({ items, viewMode = "grid" }: SubscriberFeedProps) {
  const { openPreview, modal } = useContentPreview(items);

  return (
    <>
      {viewMode === "grid" ? (
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
          {items.map(item => (
            <DashboardContentCard key={item.id} item={item} onPreview={openPreview} />
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-2xl border border-[#EDE5F8] overflow-hidden">
          {items.map(item => (
            <DashboardContentRow key={item.id} item={item} onPreview={openPreview} />
          ))}
        </div>
      )}
      {modal}
    </>
  );
}